                    </div>
                    <div>
                      <label className={labelClass}>Paid (Γé╣)</label>
                      <input type="number" min={0} value={paidFee || ""} onChange={(e) => setPaidFee(Number(e.target.value) || 0)} onWheel={(e) => (e.target as HTMLElement).blur()} className={inputClass} />
