                    </div>
                    <div>
                      <label className={labelClass}>Paid (Γé╣)</label>
                      <input type="number" min={0} value={paidFeePt || ""} onChange={(e) => setPaidFeePt(Number(e.target.value) || 0)} onWheel={(e) => (e.target as HTMLElement).blur()} className={inputClass} />
                    </div>
